using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Replace with your actual namespace
using YourNamespace.Data; // Replace with your actual namespace

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;

        public ProductController()
        {
            _context = new ApplicationDbContext();
        }

        public ActionResult Reviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .Select(r => new ReviewViewModel
                {
                    UserName = r.UserName,
                    Content = r.Content,
                    CreatedAt = r.CreatedAt
                })
                .ToList();

            return View(reviews);
        }
    }
}

// ReviewViewModel.cs
namespace YourNamespace.Models
{
    public class ReviewViewModel
    {
        public string UserName { get; set; }
        public string Content { get; set; }
        public DateTime CreatedAt { get; set; }
    }
}

// Reviews.cshtml
@model IEnumerable<YourNamespace.Models.ReviewViewModel>

@foreach (var review in Model)
{
    <div class="review">
        <h4>@review.UserName</h4>
        <p>@Html.Raw(review.Content)</p>
        <small>@review.CreatedAt.ToString("g")</small>
    </div>
}